SELECT ?year WHERE {
  ?election wdt:P31 wd:Q44206;
            wdt:P1300 ?result.
  ?result wdt:P131 wd:Q165;
          wdt:P1301 ?candidate.
  ?candidate wdt:P102 wd:Q178039.
  ?election wdt:P585 ?date.
  BIND(YEAR(?date) AS ?year)
} ORDER BY DESC(?date) LIMIT 1

